import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';
import './PatientList.css';

const PatientList = () => {
    const [patients, setPatients] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        fetchPatients();
    }, []);

    const fetchPatients = async () => {
        try {
            setLoading(true);
            const response = await axios.get('http://localhost:5000/api/patients');
            setPatients(response.data);
            setError(null);
        } catch (err) {
            setError('Error fetching patients. Please try again.');
            console.error('Error:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (patientId) => {
        if (window.confirm('Are you sure you want to delete this patient?')) {
            try {
                await axios.delete(`http://localhost:5000/api/patients/${patientId}`);
                setPatients(patients.filter(patient => patient._id !== patientId));
                alert('Patient deleted successfully');
            } catch (err) {
                alert('Error deleting patient. Please try again.');
                console.error('Error:', err);
            }
        }
    };

    const filteredPatients = patients.filter(patient => {
        const searchString = searchTerm.toLowerCase();
        return (
            patient.name.toLowerCase().includes(searchString) ||
            patient.email.toLowerCase().includes(searchString) ||
            patient.phone.toLowerCase().includes(searchString) ||
            patient.address.toLowerCase().includes(searchString)
        );
    });

    const formatDate = (dateString) => {
        const options = { year: 'numeric', month: 'long', day: 'numeric' };
        return new Date(dateString).toLocaleDateString(undefined, options);
    };

    if (loading) {
        return (
            <div className="loading">
                <h2>Loading Patients...</h2>
                <p>Please wait while we fetch the patient records.</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="error">
                <h2>Error</h2>
                <p>{error}</p>
                <button onClick={fetchPatients} className="retry-btn">
                    Try Again
                </button>
            </div>
        );
    }

    return (
        <div className="patient-list">
            <div className="patient-list-header">
                <h2>Patients</h2>
                <Link to="/add-patient" className="add-patient-btn">
                    Add New Patient
                </Link>
            </div>

            <div className="search-bar">
                <input
                    type="text"
                    placeholder="Search patients..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>

            {filteredPatients.length === 0 ? (
                <div className="no-patients">
                    <h3>No Patients Found</h3>
                    <p>There are no patients matching your search criteria.</p>
                </div>
            ) : (
                <div className="patients-grid">
                    {filteredPatients.map((patient) => (
                        <div key={patient._id} className="patient-card">
                            <div className="patient-header">
                                <h3>{patient.name}</h3>
                                <span className="patient-id">ID: {patient._id.slice(-6)}</span>
                            </div>

                            <div className="patient-details">
                                <div className="detail-group">
                                    <h4>Personal Information</h4>
                                    <p><strong>Email:</strong> {patient.email}</p>
                                    <p><strong>Phone:</strong> {patient.phone}</p>
                                    <p><strong>Age:</strong> {patient.age}</p>
                                    <p><strong>Gender:</strong> {patient.gender}</p>
                                    <p><strong>Address:</strong> {patient.address}</p>
                                </div>

                                <div className="detail-group">
                                    <h4>Medical Information</h4>
                                    <p><strong>Medical History:</strong> {patient.medicalHistory || 'No medical history recorded'}</p>
                                    <p><strong>Registration Date:</strong> {formatDate(patient.registrationDate)}</p>
                                </div>
                            </div>

                            <div className="patient-actions">
                                <Link 
                                    to={`/patients/${patient._id}/appointments`}
                                    className="view-appointments-btn"
                                >
                                    View Appointments
                                </Link>
                                <Link 
                                    to={`/edit-patient/${patient._id}`}
                                    className="edit-btn"
                                >
                                    Edit Details
                                </Link>
                                <button
                                    onClick={() => handleDelete(patient._id)}
                                    className="delete-btn"
                                >
                                    Delete
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default PatientList;
